import sys

def is_balanced(s):
    stack = []
    bracket_map = {'(': ')', '[': ']', '{': '}'}
    opening = set(bracket_map.keys())
    closing = set(bracket_map.values())

    for char in s:
        if char in opening:
            stack.append(char)
        elif char in closing:
            if not stack or bracket_map[stack.pop()] != char:
                return False

    return len(stack) == 0

