def evaluate_rpn(expression):
    tokens = expression.split()
    stack = []

    for token in tokens:
        if token in ['+', '-', '*', '/']:
            b = stack.pop()
            a = stack.pop()

            if token == '+':
                result = a + b
            elif token == '-':
                result = a - b
            elif token == '*':
                result = a * b
            elif token == '/':
                result = int(a / b)

            stack.append(result)
        else:
            stack.append(int(token))

    return stack[0]

