import sys

def caesar_cipher(message, shift, encode=True):
    result = []

    if not encode:
        shift = -shift

    for char in message:
        if char.isupper():
            shifted = chr((ord(char) - ord('A') + shift) % 26 + ord('A'))
            result.append(shifted)
        elif char.islower():
            shifted = chr((ord(char) - ord('a') + shift) % 26 + ord('a'))
            result.append(shifted)
        else:
            result.append(char)

    return ''.join(result)

