import (
	"fmt"
	"os"
	"strconv"
)

func main() {
	if len(os.Args) < 4 {
		fmt.Println("Usage: program <encode|decode> <shift> <message>")
		os.Exit(1)
	}

	mode := os.Args[1]
	shift, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Println("Error: shift must be an integer")
		os.Exit(1)
	}
	message := os.Args[3]

	if mode == "decode" {
		shift = -shift
	}

	shift = ((shift % 26) + 26) % 26

	result := ""
	for _, char := range message {
		if char >= 'a' && char <= 'z' {
			shifted := (int(char-'a') + shift) % 26
			result += string(rune('a' + rune(shifted)))
		} else if char >= 'A' && char <= 'Z' {
			shifted := (int(char-'A') + shift) % 26
			result += string(rune('A' + rune(shifted)))
		} else {
			result += string(char)
		}
	}

	fmt.Println(result)
}
